#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e6+10;
int maxi[MAXN],mini[MAXN],head1,head2,tail1,tail2;
int maxx[MAXN],minx[MAXN],a[MAXN];
int main()
{
	int n,k,x=0;
	cin>>n>>k;
	int tot=0;
	head1=head2=1,tail1=tail2=0;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		while(tail1>=head1&&a[i]<=a[mini[tail1]]){
			tail1--;
		}
		while(tail2>=head2&&a[i]>=a[maxi[tail2]]){
			tail2--;
		}
		tot++;
		maxi[++tail2]=i;
		mini[++tail1]=i;
		if(mini[head1]<=i-k)head1++;
		if(maxi[head2]<=i-k)head2++;
//		cout<<mini.front()<<" ";
		maxx[tot]=maxi[head2];
		minx[tot]=mini[head1];
	}
	for(int i=k;i<=tot;i++)cout<<a[minx[i]]<<" ";
	cout<<endl;
	for(int i=k;i<=tot;i++)cout<<a[maxx[i]]<<" ";
}
